mapper.select:
SELECT issue_code , project_name , title , priority , status , progress , started_at , resolved_at , assignee_name , duration , project_code , created_on FROM gantt_view
AND status = #{status}
AND assignee_name = #{assigneeName}
AND project_code = #{projectCode}
AND created_on BETWEEN #{createdOnFrom} AND #{createdOnTo}
ORDER BY issue_code
